  const course = 'Half Stack application development'
  const parts = [
    {
      name: 'Fundamentals of React',
      exercises: 10
    },
    {
      name: 'Using props to pass data',
      exercises: 7
    },
    {
      name: 'State of a component',
      exercises: 14
    }
  ]
  const exercises1 = 10
  const exercises2 = 7
  const exercises3 = 14
  return (
    <div>
      <Header course={course} />

      <ContentMix partContentParse={parts} />
      <Content contentTogether={parts} />
      {/* <Content name={part1.name} exercises={part1.exercises} />

      <Content name={part2.name} exercises={part2.exercises} />
      <Content name={part3.name} exercises={part3.exercises} />
      <Total exercises1={exercises1} exercises2={exercises2} exercises3={exercises3} /> */}
    </div >
  )
}
const Header = (props) => {
  console.log(props)
  return (
    <h1>{props.course}</h1>
  )
}
const ContentMix = (props) => {
  console.log(props)
  return (
    <p>
      {props.partContentParse.name}
      {" "}
      {props.partContentParse.exercises}
      {/* {props.partContentParse1.exercises} */}
    </p>
  )
}
const Content = (props) => {
  console.log(props)
  return (
    <>
      <ContentMix partContentParse={props.contentTogether[0]} />
      <ContentMix partContentParse={props.contentTogether[1]} />
      <ContentMix partContentParse={props.contentTogether[2]} />
    </>
    // <p>{props.name}{" "}{props.exercises}</p>
  )
}
const Numbers = (props) => {
  console.log(props)
  return (
    <p>
      {props.partContentParse.exercises}
      {/* {props.partContentParse1.exercises} */}
    </p>
  )
}
const Total = (props) => {
  return (
    <p>
      Number of exercises{" "}{props.exercises1 + props.exercises2 + props.exercises3}
    </p>
    //   <p>Number of exercises{" "}
    //     {props.exercises1 + props.exercises2 + props.exercises3}
    //   </p>
  )
}
export default App
